import{_ as e,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const M=JSON.parse('{"title":"Mark1铁罐装甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/0.无支线/Mark1铁罐装甲.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/0.无支线/Mark1铁罐装甲.md"}'),d={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/0.无支线/Mark1铁罐装甲.md"};function k(b,a,l,p,_,i){return t(),n("div",null,[...a[0]||(a[0]=[r("h1",{id:"mark1铁罐装甲",tabindex:"-1"},[s("Mark1铁罐装甲 "),r("a",{class:"header-anchor",href:"#mark1铁罐装甲","aria-label":'Permalink to "Mark1铁罐装甲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="mark1铁罐装甲-1" tabindex="-1">Mark1铁罐装甲 <a class="header-anchor" href="#mark1铁罐装甲-1" aria-label="Permalink to &quot;Mark1铁罐装甲&quot;">​</a></h1><p>Mark1铁罐装甲<br> 价格：2000<br> 前提：力量5<br> Mark1是托尼·斯塔克创造的第一个机甲，是目前为止最重和最弱的装甲之一，这也是唯一一个装备火焰喷射器的装甲。Mark1重约1500磅（约680公斤），由防弹铁、铜、镁合金和一些皮具组成，外观非常粗糙，且没有完成全遮盖，这是因为托尼创造装甲时，各种资源有限。<br> 因为没有后续版本的智能AI贾维斯，且制作粗糙，动力反馈效果很差，所以角色的力量必须到达5，才可以正常穿戴本装甲。<br> Mark1机甲实际上是利用杰里科导弹部件建造，其装甲能应付小型武器射击。Mark1装甲没有气动控制其飞行，但是机甲底部装备了喷气靴，飞行动力从杰里科导弹的推进系统中提取固态火箭燃料来提供。Mark1右臂装有火焰喷射器，由装甲背后的小煤气罐提供燃料，然后通过手动控制点燃，制造出一个极具破坏性的火焰。</p><p>本质：科技本质<br> 载具类型：重型载具 载具专业：重型载具<br> 速度：30米<br> 体积：8<br> 结构值：16<br> 装甲：9 且具有基于装甲的[防弹]能力。<br> 动力：方舟反应堆（1.5克的钯元素圈），视为无限动力。<br> 载员情况：<br> Mark1铁罐装甲由1名体积小于等于6的使用者员使用。<br> Mark1右臂的火焰喷射器，视为无支线的单兵火焰喷射器，武器伤害4L，威猛5，在15米内使用额外获得高速2，射程40米，如果一次性消耗一半罐的油量，还可以获得2DP器械加值。<br> 消耗燃料（1分10罐，一罐可喷射12次），造成火焰伤害。<br> 因为原始版本的Mark1没有AI，所以采用枪械攻击检定，采用射击：喷射专业，而不是一般的载具攻击检定。</p><p>Mark1双脚配备有喷气靴，可以用一个标准动作启动，选择一个方向，将自己弹射出去。发射出去后，为了减轻重量，盔甲自动解体，影片内无法再度使用。飞行过程中处于无助状态，无法转向，只能飞向固定地点或目标。最大射程 3600米，此时需要60轮才能抵达目的地（每轮60米）。 若击中目标，你将对目标进行一次冲撞。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const h=e(d,[["render",k]]);export{M as __pageData,h as default};
